import { FeatureCollection } from 'geojson';
import { useCallback, useEffect, useState } from 'react';

import { useMapViewProviderContext } from './use-map-view-provider-context.js';
import type { BaseLayerRules } from '../types/base-layer.js';
import { applyFeatureFilterRules } from '../utils/apply-feature-filter-rules.js';
import {
  getCountryRegionsRules,
  getRegionsRules,
  getWorldViewRules,
} from '../utils/base-layer-rules.js';
import {
  fetchCountryFeatures,
  fetchWorldViewFeatures,
} from '../utils/fetch-base-layer-features.js';
import { fetchClientConfigMapEnabled } from '../utils/fetch-client-config-map-enabled.js';
import { getBaseLayerShapesRequestConfig } from '../utils/get-base-layer-shapes-request-config.js';
import { getTenantCountryCode } from '../utils/get-tenant-country-code.js';
import { mergeFeatureCollections } from '../utils/merge-feature-collections.js';

export const useLoadMapBaseLayer = (baseLayerConfig: BaseLayerRules) => {
  const [isFetchingFeatures, setIsFetchingFeatures] = useState(true);
  const [isMapEnabled, setIsMapEnabled] = useState(false);
  const [baseFeatureCollection, setBaseFeatureCollection] = useState<
    FeatureCollection | undefined
  >(undefined);
  const [error, setError] = useState<boolean>(false);

  const {
    countryCode: providerCountryCode,
    displayWorldMap: providerDisplayWorldMap,
  } = useMapViewProviderContext();

  const getData = useCallback(async () => {
    setIsFetchingFeatures(true);

    const isMapEnabledResponse =
      providerDisplayWorldMap ?? (await fetchClientConfigMapEnabled());

    setIsMapEnabled(isMapEnabledResponse);

    try {
      if (isMapEnabledResponse) {
        const tenantCountryCode =
          providerCountryCode ?? (await getTenantCountryCode());

        const { includeWorldView, countryRegions } =
          getBaseLayerShapesRequestConfig(baseLayerConfig.include);

        const featuresRequests: Promise<FeatureCollection>[] = [];

        if (includeWorldView) {
          const worldViewRules = getWorldViewRules(baseLayerConfig);
          const worldViewRequest = fetchWorldViewFeatures(
            tenantCountryCode,
          ).then(applyFeatureFilterRules(worldViewRules));
          featuresRequests.push(worldViewRequest);
        }

        if (countryRegions.length > 0) {
          const regionsRules = getRegionsRules(baseLayerConfig);
          countryRegions.forEach((countryCode: string) => {
            const countryRules = getCountryRegionsRules(
              regionsRules,
              countryCode,
            );
            const countryRequest = fetchCountryFeatures(
              tenantCountryCode,
              countryCode,
            ).then(applyFeatureFilterRules(countryRules, countryCode));
            featuresRequests.push(countryRequest);
          });
        }

        const featureCollections = await Promise.all(featuresRequests);

        setBaseFeatureCollection(mergeFeatureCollections(featureCollections));
      }
    } catch {
      setError(true);
    }

    setIsFetchingFeatures(false);
  }, [
    baseLayerConfig.include,
    baseLayerConfig.exclude,
    providerCountryCode,
    providerDisplayWorldMap,
  ]);

  useEffect(() => {
    getData();
  }, [getData]);
  return { isFetchingFeatures, baseFeatureCollection, isMapEnabled, error };
};
